/* HADO app 3.0.0.0 Update05: candidate tray staging UI with safe formation-screen handoff */
(()=>{'use strict';
const KEY='hado.typeCandidateTray.v1';
const TYPE_KEY='hado.typeEntry.selection.v1';
const ADD='hado:formation-candidate-tray-add';
const ROLE_LABELS={main_general:'主将',vice_general:'副将',support_general:'補佐',attendant:'侍従',equipment:'装備',formation:'陣形',siege_weapon:'兵器',warhorse:'名馬',warhorse_skill:'軍馬技能',candidate:'候補'};
const esc=s=>String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
const clean=s=>String(s??'').normalize('NFKC').replace(/[\r\n\t]+/g,' ').trim();
const readJson=(key,fallback)=>{try{return JSON.parse(localStorage.getItem(key)||'')||fallback}catch{return fallback}};
function currentType(){const v=readJson(TYPE_KEY,{});return {typeId:clean(v.typeId),typeName:clean(v.typeName||v.typeLabel||v.typeId)}}
function load(){const v=readJson(KEY,{items:[]});return Array.isArray(v.items)?v.items:[]}
function save(items){localStorage.setItem(KEY,JSON.stringify({schemaVersion:'1.0',updatedAt:new Date().toISOString(),items:items.slice(0,60)}));refresh()}
function idOf(v){return [clean(v.typeId),clean(v.roleId),clean(v.name)].join('::')}
function addItem(v){const t=currentType(),row={typeId:clean(v?.typeId||t.typeId),typeName:clean(v?.typeName||t.typeName),roleId:clean(v?.roleId||'candidate'),name:clean(v?.name),source:clean(v?.source||'型候補一覧'),addedAt:new Date().toISOString()};if(!row.name)return;row.id=idOf(row);const items=load();if(items.some(x=>x.id===row.id)){notice(`${row.name} は候補トレイに登録済みです。`);return}items.unshift(row);save(items);notice(`${row.name} を候補トレイへ追加しました。`)}
function removeItem(id){save(load().filter(v=>v.id!==id))}
function notice(message){let el=document.getElementById('hct-toast');if(!el){el=document.createElement('div');el.id='hct-toast';el.style.cssText='position:fixed;right:18px;bottom:184px;z-index:100002;max-width:min(420px,88vw);padding:10px 13px;border-radius:10px;background:#0f172a;color:#fff;font-size:13px;box-shadow:0 8px 20px rgba(0,0,0,.22)';document.body.appendChild(el)}el.textContent=message;clearTimeout(el._timer);el._timer=setTimeout(()=>el.remove(),2600)}
function style(){if(document.getElementById('hct-style'))return;const e=document.createElement('style');e.id='hct-style';e.textContent=`#hct-open{position:fixed;right:18px;bottom:126px;z-index:99990;border:1px solid #0f766e;border-radius:999px;padding:11px 17px;background:#fff;color:#0f766e;font-weight:700;cursor:pointer;box-shadow:0 6px 18px rgba(15,118,110,.16)}#hct-count{display:inline-flex;align-items:center;justify-content:center;min-width:22px;height:22px;margin-left:6px;border-radius:999px;background:#0f766e;color:#fff;font-size:12px}#hct-overlay{position:fixed;inset:0;z-index:99993;background:#0f172a94;display:flex;align-items:center;justify-content:center;padding:16px}#hct-modal{width:min(920px,100%);max-height:92dvh;background:#fff;border-radius:18px;display:grid;grid-template-rows:auto auto minmax(0,1fr) auto;overflow:hidden;color:#172033}.hct-p{padding:14px 18px}.hct-head,.hct-foot{display:flex;justify-content:space-between;gap:10px;align-items:center}.hct-head{border-bottom:1px solid #d9e1ec}.hct-body{overflow:auto}.hct-note,.hct-meta{font-size:12px;color:#64748b;line-height:1.6}.hct-list{display:grid;gap:8px}.hct-item{border:1px solid #d8e0eb;border-radius:12px;padding:11px;display:grid;gap:7px}.hct-title{font-weight:700}.hct-actions{display:flex;gap:7px;flex-wrap:wrap}.hct-btn{border:1px solid #cbd5e1;background:#fff;border-radius:9px;padding:8px 11px;cursor:pointer}.hct-btn.primary{border-color:#0f766e;background:#f0fdfa;color:#0f766e;font-weight:700}.hct-btn.danger{border-color:#fca5a5;background:#fff7f7;color:#b91c1c}.hct-badge{display:inline-block;border-radius:999px;padding:2px 8px;background:#ecfeff;color:#155e75;font-size:11px;margin-right:6px}.hct-empty{padding:24px;border:1px dashed #cbd5e1;border-radius:12px;color:#64748b;text-align:center}.hct-add-from-candidate{margin-top:8px}@media(max-width:720px){#hct-overlay{padding:0}#hct-modal{width:100%;height:100dvh;max-height:none;border-radius:0}.hct-p{padding:12px}}`;document.head.appendChild(e)}
function close(){document.getElementById('hct-overlay')?.remove()}
function goFormation(row){document.getElementById('mainTabFormationBtn')?.click();close();notice(`${row.name} を候補として確認してください。配置確定は部隊編成画面で行います。`)}
function itemHtml(row){const role=ROLE_LABELS[row.roleId]||row.roleId||'候補';return `<div class="hct-item"><div><span class="hct-badge">${esc(role)}</span><span class="hct-title">${esc(row.name)}</span></div><div class="hct-meta">型: ${esc(row.typeName||row.typeId||'未指定')} / 追加元: ${esc(row.source||'型候補一覧')}</div><div class="hct-actions"><button type="button" class="hct-btn primary" data-hct-place="${esc(row.id)}">部隊編成画面で確認</button><button type="button" class="hct-btn danger" data-hct-remove="${esc(row.id)}">削除</button></div></div>`}
function render(){const m=document.getElementById('hct-modal');if(!m)return;const rows=load();m.innerHTML=`<div class="hct-p hct-head"><div><h2>候補トレイ</h2><div class="hct-note">3.0.0.0 Update05 / 気になる候補を一時保存</div></div><button type="button" class="hct-btn" data-hct-close>閉じる</button></div><div class="hct-p hct-note">候補トレイは検討用です。部隊へ直接配置しません。「部隊編成画面で確認」を押した後、配置先・侍従・兵科・射程・装備重複などを既存画面で確認して登録してください。</div><div class="hct-p hct-body"><div class="hct-list">${rows.length?rows.map(itemHtml).join(''):'<div class="hct-empty">候補トレイは空です。型候補一覧から追加してください。</div>'}</div></div><div class="hct-p hct-foot"><div class="hct-note">候補数: ${rows.length}件</div><div class="hct-actions">${rows.length?'<button type="button" class="hct-btn danger" data-hct-clear>すべて削除</button>':''}<button type="button" class="hct-btn" data-hct-close>閉じる</button></div></div>`;m.querySelectorAll('[data-hct-close]').forEach(b=>b.onclick=close);m.querySelectorAll('[data-hct-remove]').forEach(b=>b.onclick=()=>{removeItem(b.dataset.hctRemove);render()});m.querySelectorAll('[data-hct-place]').forEach(b=>b.onclick=()=>{const row=load().find(v=>v.id===b.dataset.hctPlace);if(row)goFormation(row)});m.querySelectorAll('[data-hct-clear]').forEach(b=>b.onclick=()=>{save([]);render()})}
function open(){style();close();const o=document.createElement('div');o.id='hct-overlay';o.innerHTML='<section id="hct-modal" role="dialog" aria-modal="true" aria-label="候補トレイ"></section>';o.onclick=e=>{if(e.target===o)close()};document.body.appendChild(o);render()}
function refresh(){const c=document.getElementById('hct-count');if(c)c.textContent=String(load().length)}
function roleFromModal(){return document.querySelector('#htc-modal .htc-tab.on')?.dataset.role||'candidate'}
function patchCandidateBrowser(){document.querySelectorAll('#htc-modal .htc-item').forEach(card=>{if(card.querySelector('.hct-add-from-candidate'))return;const name=clean(card.querySelector('.htc-title')?.textContent);if(!name)return;const b=document.createElement('button');b.type='button';b.className='htc-btn hct-add-from-candidate';b.textContent='候補トレイへ追加';b.onclick=e=>{e.preventDefault();e.stopPropagation();addItem({roleId:roleFromModal(),name,source:'型候補一覧'})};card.appendChild(b)})}
function mount(){if(document.getElementById('hct-open'))return;style();const b=document.createElement('button');b.id='hct-open';b.type='button';b.innerHTML='候補トレイ <span id="hct-count">0</span>';b.onclick=open;document.body.appendChild(b);refresh();patchCandidateBrowser();new MutationObserver(()=>patchCandidateBrowser()).observe(document.body,{childList:true,subtree:true});addEventListener('storage',refresh)}
addEventListener(ADD,e=>addItem(e.detail||{}));
if(document.readyState==='loading')addEventListener('DOMContentLoaded',mount);else mount();
})();
